function candidate(...segments) {
  for (const part of segments) {
    if (typeof part !== "string") {
      throw new TypeError("Path segment must be a string");
    }
  }

  const kept = segments.filter((part) => part.length > 0);
  if (kept.length === 0) {
    return ".";
  }

  const input = kept.join("/");
  const absolute = input.startsWith("/");
  const trailing = input.endsWith("/");
  const stack = [];

  for (const piece of input.split("/")) {
    if (piece === "" || piece === ".") {
      continue;
    }
    if (piece === "..") {
      if (stack.length > 0 && stack[stack.length - 1] !== "..") {
        stack.pop();
      } else if (!absolute) {
        stack.push("..");
      }
    } else {
      stack.push(piece);
    }
  }

  let output = stack.join("/");
  if (absolute) {
    output = "/" + output;
  }
  if (output === "") {
    output = absolute ? "/" : ".";
  }
  if (trailing && output !== "/" && output !== ".") {
    output += "/";
  }
  return output;
}
